// Package service authn module — HTTP handlers for AuthnService.
//
// This file implements the v1.AuthnServiceHTTPServer interface generated by
// protoc-gen-go-http from api/authn/v1/authn.proto. It also registers two
// browser-friendly 302 redirect routes (/v1/authn/login and /v1/authn/logout)
// that the proto cannot express because google.api.http only supports JSON
// responses, not raw HTTP 302s.
//
// Layering contract (AGENTS.md):
//   - service imports: api/* (proto DTOs) and biz (domain objects + usecases).
//   - service MUST NOT import: data, conf, or any kernel Runtime type.
//
// The service layer's job per RPC:
//  1. Read request fields (including Authorization header for Me).
//  2. Convert proto DTO → biz DO.
//  3. Call the corresponding biz.AuthnUsecase method.
//  4. Convert biz DO → proto DTO.
//  5. Return.
//
// The service layer does NOT do any authn/authz enforcement itself. LoginURL,
// Exchange, Refresh, LogoutURL, Revoke, and Introspect are skipped by the
// transport authn middleware because they validate the token/code carried in
// the request body. Me still requires the Authorization header and is verified
// again in the biz layer so the local revoke blacklist is honored.

package service

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"

	v1 "github.com/aisphereio/aisphere-hub/api/authn/v1"
	"github.com/aisphereio/aisphere-hub/internal/biz"

	"github.com/aisphereio/kernel/authn"
	khttp "github.com/aisphereio/kernel/transportx/http"
	"google.golang.org/protobuf/types/known/structpb"
	"google.golang.org/protobuf/types/known/timestamppb"
)

// timeNow is a small indirection so tests can stub it. Default returns
// time.Now().
var timeNow = func() time.Time { return time.Now() }

// AuthnService implements both v1.AuthnServiceHTTPServer (proto-generated
// HTTP routes) and v1.AuthnServiceServer (proto-generated gRPC routes).
//
// We embed v1.UnimplementedAuthnServiceServer to satisfy the
// `mustEmbedUnimplementedAuthnServiceServer()` constraint required by the
// generated gRPC interface (forward-compatibility: if a new RPC is added
// to the proto and we forget to implement it, callers get a clean
// "Unimplemented" status instead of a compile error or a nil-panic at
// runtime). The HTTP interface does not require this embed.
type AuthnService struct {
	v1.UnimplementedAuthnServiceServer

	uc *biz.AuthnUsecase
}

// NewAuthnService creates a new AuthnService.
func NewAuthnService(uc *biz.AuthnUsecase) *AuthnService {
	return &AuthnService{uc: uc}
}

// RegisterHTTPServer registers the proto-generated HTTP routes and the two
// browser-friendly 302 redirect routes.
//
// The 302 routes exist because copying a JSON-encoded URL out of a response
// body unescapes "&" into "\u0026" in many browsers and terminals, which
// breaks the redirect URL. The handlers read the same query parameters as
// the JSON RPCs but return a 302 instead of a JSON body.
//
// The 302 handlers are wrapped in recoverHandler so a panic inside the
// handler (e.g. nil-deref in query parsing) returns a 500 instead of
// crashing the process. The kernel middleware chain does not apply to
// HandleFunc-registered routes, so each manual handler must be wrapped
// explicitly.
func (s *AuthnService) RegisterHTTPServer(srv *khttp.Server) {
	v1.RegisterAuthnServiceHTTPServer(srv, s)
	srv.HandleFunc("/v1/authn/login", s.recoverHandler(s.handleLoginRedirect))
	srv.HandleFunc("/v1/authn/logout", s.recoverHandler(s.handleLogoutRedirect))
}

// LoginURL implements v1.AuthnServiceHTTPServer.LoginURL.
func (s *AuthnService) LoginURL(ctx context.Context, req *v1.LoginURLRequest) (*v1.LoginURLResponse, error) {
	url, err := s.uc.LoginURL(ctx, biz.AuthnLoginURLRequest{
		RedirectURI: req.GetRedirectUri(),
		State:       req.GetState(),
		Scope:       req.GetScope(),
		Prompt:      req.GetPrompt(),
		OrgID:       req.GetOrgId(),
		AppID:       req.GetAppId(),
	})
	if err != nil {
		return nil, err
	}
	return &v1.LoginURLResponse{LoginUrl: url}, nil
}

// Exchange implements v1.AuthnServiceHTTPServer.Exchange.
func (s *AuthnService) Exchange(ctx context.Context, req *v1.ExchangeRequest) (*v1.TokenResponse, error) {
	out, err := s.uc.Exchange(ctx, biz.AuthnExchangeURLRequest{
		Code:         req.GetCode(),
		RedirectURI:  req.GetRedirectUri(),
		State:        req.GetState(),
		CodeVerifier: req.GetCodeVerifier(),
		OrgID:        req.GetOrgId(),
		AppID:        req.GetAppId(),
	})
	if err != nil {
		return nil, err
	}
	return tokenDOToDTO(out), nil
}

// Refresh implements v1.AuthnServiceHTTPServer.Refresh.
func (s *AuthnService) Refresh(ctx context.Context, req *v1.RefreshRequest) (*v1.TokenResponse, error) {
	out, err := s.uc.Refresh(ctx, biz.AuthnRefreshRequest{
		RefreshToken: req.GetRefreshToken(),
		Scope:        req.GetScope(),
		OrgID:        req.GetOrgId(),
		AppID:        req.GetAppId(),
	})
	if err != nil {
		return nil, err
	}
	return tokenDOToDTO(out), nil
}

// LogoutURL implements v1.AuthnServiceHTTPServer.LogoutURL.
//
// As documented in the proto, when the request body does not include
// access_token, the implementation falls back to the Authorization header
// so that callers using the JSON RPC (rather than the 302 route) still
// trigger the local blacklist side effect.
func (s *AuthnService) LogoutURL(ctx context.Context, req *v1.LogoutURLRequest) (*v1.LogoutURLResponse, error) {
	accessToken := req.GetAccessToken()
	if accessToken == "" {
		accessToken = bearerTokenFromContext(ctx)
	}
	url, err := s.uc.LogoutURL(ctx, biz.AuthnLogoutURLRequest{
		PostLogoutRedirectURI: req.GetPostLogoutRedirectUri(),
		IDTokenHint:           req.GetIdTokenHint(),
		State:                 req.GetState(),
		AccessToken:           accessToken,
		OrgID:                 req.GetOrgId(),
		AppID:                 req.GetAppId(),
	})
	if err != nil {
		return nil, err
	}
	return &v1.LogoutURLResponse{LogoutUrl: url}, nil
}

// Revoke implements v1.AuthnServiceHTTPServer.Revoke.
func (s *AuthnService) Revoke(ctx context.Context, req *v1.RevokeRequest) (*v1.RevokeResponse, error) {
	out, err := s.uc.Revoke(ctx, biz.AuthnRevokeRequest{
		Token:     req.GetToken(),
		TokenType: req.GetTokenType(),
		OrgID:     req.GetOrgId(),
		AppID:     req.GetAppId(),
	})
	if err != nil {
		return nil, err
	}
	if out == nil {
		out = &biz.AuthnRevokeResult{}
	}
	return &v1.RevokeResponse{
		Revoked:    out.Revoked,
		IdpRevoked: out.IDPRevoked,
		Message:    out.Message,
	}, nil
}

// Introspect implements v1.AuthnServiceHTTPServer.Introspect.
func (s *AuthnService) Introspect(ctx context.Context, req *v1.IntrospectRequest) (*v1.IntrospectResponse, error) {
	out, err := s.uc.Introspect(ctx, biz.AuthnIntrospectRequest{
		Token:     req.GetToken(),
		TokenType: req.GetTokenType(),
		Issuer:    req.GetIssuer(),
		Audience:  req.GetAudience(),
		OrgID:     req.GetOrgId(),
		AppID:     req.GetAppId(),
	})
	if err != nil {
		return nil, err
	}
	if out == nil {
		return &v1.IntrospectResponse{Active: false}, nil
	}
	resp := &v1.IntrospectResponse{
		Active: out.Active,
		Scope:  out.Scope,
	}
	if !out.ExpiresAt.IsZero() {
		resp.ExpiresAt = timestamppb.New(out.ExpiresAt)
	}
	if !out.IssuedAt.IsZero() {
		resp.IssuedAt = timestamppb.New(out.IssuedAt)
	}
	if out.Active {
		resp.Principal = principalToDTO(out.Principal)
	}
	return resp, nil
}

// Me implements v1.AuthnServiceHTTPServer.Me.
//
// The access token is read from the Authorization header (Bearer scheme).
// The biz layer verifies it through the kernel Authenticator and checks the
// local blacklist.
func (s *AuthnService) Me(ctx context.Context, req *v1.MeRequest) (*v1.MeResponse, error) {
	accessToken := bearerTokenFromContext(ctx)
	principal, err := s.uc.Me(ctx, accessToken)
	if err != nil {
		return nil, err
	}
	return &v1.MeResponse{Principal: principalToDTO(principal)}, nil
}

// --- browser-friendly 302 redirect handlers ---

// handleLoginRedirect reads the same query parameters as LoginURL and
// responds with a 302 redirect to the IdP login URL. This avoids the
// "\u0026" escaping problem that occurs when a browser copies a URL out
// of a JSON response body.
func (s *AuthnService) handleLoginRedirect(w http.ResponseWriter, r *http.Request) {
	q := r.URL.Query()
	url, err := s.uc.LoginURL(r.Context(), biz.AuthnLoginURLRequest{
		RedirectURI: firstNonEmpty(q.Get("redirect_uri"), q.Get("redirectUri")),
		State:       q.Get("state"),
		Scope:       q.Get("scope"),
		Prompt:      q.Get("prompt"),
		OrgID:       firstNonEmpty(q.Get("org_id"), q.Get("orgId")),
		AppID:       firstNonEmpty(q.Get("app_id"), q.Get("appId")),
	})
	if err != nil {
		writeAuthnError(w, http.StatusBadRequest, err)
		return
	}
	http.Redirect(w, r, url, http.StatusFound)
}

// handleLogoutRedirect reads the same query parameters as LogoutURL and
// responds with a 302 redirect to the IdP logout URL. The access token is
// read from the Authorization header (the body would not be available on a
// GET request anyway).
func (s *AuthnService) handleLogoutRedirect(w http.ResponseWriter, r *http.Request) {
	q := r.URL.Query()
	accessToken := bearerTokenFromHeader(r.Header.Get("Authorization"))
	url, err := s.uc.LogoutURL(r.Context(), biz.AuthnLogoutURLRequest{
		PostLogoutRedirectURI: firstNonEmpty(q.Get("post_logout_redirect_uri"), q.Get("postLogoutRedirectUri")),
		IDTokenHint:           firstNonEmpty(q.Get("id_token_hint"), q.Get("idTokenHint")),
		State:                 q.Get("state"),
		AccessToken:           accessToken,
		OrgID:                 firstNonEmpty(q.Get("org_id"), q.Get("orgId")),
		AppID:                 firstNonEmpty(q.Get("app_id"), q.Get("appId")),
	})
	if err != nil {
		writeAuthnError(w, http.StatusBadRequest, err)
		return
	}
	http.Redirect(w, r, url, http.StatusFound)
}

// recoverHandler wraps an http.HandlerFunc so a panic returns a 500 response
// (and logs to stderr) instead of crashing the process. The kernel middleware
// chain's recovery middleware does not see HandleFunc-registered routes, so
// each manual handler must be wrapped explicitly.
func (s *AuthnService) recoverHandler(h http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if rec := recover(); rec != nil {
				writeAuthnError(w, http.StatusInternalServerError, fmt.Errorf("internal server error: %v", rec))
			}
		}()
		h(w, r)
	}
}

// --- DTO conversion helpers ---

func tokenDOToDTO(t *biz.AuthnToken) *v1.TokenResponse {
	if t == nil {
		return &v1.TokenResponse{}
	}
	expiresIn := int64(0)
	if !t.ExpiresAt.IsZero() {
		expiresIn = int64(t.ExpiresAt.Sub(timeNow()).Seconds())
		if expiresIn < 0 {
			expiresIn = 0
		}
	}
	return &v1.TokenResponse{
		AccessToken:  t.AccessToken,
		RefreshToken: t.RefreshToken,
		IdToken:      t.IDToken,
		TokenType:    t.TokenType,
		ExpiresIn:    expiresIn,
		Scope:        t.Scope,
	}
}

// principalToDTO maps kernel authn.Principal onto the proto Principal.
//
// The kernel Principal has more fields than the proto Principal (Provider,
// ExternalID, Issuer, Audience, TenantID, AppID, IssuedAt). We intentionally
// drop them on the public API surface; they are useful internally but not
// to typical frontend consumers. If a future use case needs them, add proto
// fields rather than exposing the kernel struct verbatim.
//
// Sensitive attributes (e.g. casdoor "access_token" set in
// kernel/authn/casdoor/token.go:principalFromClaims) are filtered out before
// returning to frontend clients.
func principalToDTO(p authn.Principal) *v1.Principal {
	if !p.IsAuthenticated() {
		return &v1.Principal{
			SubjectType:     p.SubjectType,
			IsAuthenticated: false,
			AuthMethod:      p.AuthMethod,
		}
	}
	out := &v1.Principal{
		SubjectType:     p.SubjectType,
		SubjectId:       p.SubjectID,
		Username:        p.Username,
		Name:            p.Name,
		DisplayName:     p.Name, // kernel Principal has no DisplayName; use Name
		Email:           p.Email,
		Avatar:          "", // kernel Principal has no Avatar; populate from Attributes if needed
		OrgId:           p.OrgID,
		ProjectId:       p.ProjectID,
		Roles:           append([]string(nil), p.Roles...),
		Groups:          append([]string(nil), p.Groups...),
		IsAuthenticated: true,
		Phone:           p.Phone,
		Scopes:          append([]string(nil), p.Scopes...),
		AuthMethod:      p.AuthMethod,
	}
	if !p.ExpiresAt.IsZero() {
		out.ExpiresAt = timestamppb.New(p.ExpiresAt)
	}
	// Filter sensitive attributes before exposing to clients.
	if attrs := filterAttributes(p.Attributes); attrs != nil && len(attrs.GetFields()) > 0 {
		out.Attributes = attrs
	}
	return out
}

// filterAttributes converts kernel authn.AttributeSet to proto Struct while
// removing keys that must not leak to the frontend. The current blocklist:
//   - access_token:  set by kernel casdoor adapter; would leak the bearer
//     token to anyone reading /me
//   - casdoor_token_type: internal marker, not useful to clients
//
// Additional keys can be added here without breaking clients because Struct
// is forward-compatible.
func filterAttributes(in authn.AttributeSet) *structpb.Struct {
	if len(in) == 0 {
		return nil
	}
	filtered := make(map[string]any, len(in))
	for k, v := range in {
		if isSensitiveAttribute(k) {
			continue
		}
		filtered[k] = v
	}
	if len(filtered) == 0 {
		return nil
	}
	st, err := structpb.NewStruct(filtered)
	if err != nil {
		return nil
	}
	return st
}

func isSensitiveAttribute(key string) bool {
	switch key {
	case "access_token", "casdoor_token_type", "refresh_token", "id_token":
		return true
	}
	return false
}

// --- HTTP helpers ---

// bearerTokenFromContext extracts the Bearer token from the Authorization
// header on a kernel http.Context.
func bearerTokenFromContext(ctx context.Context) string {
	type headerer interface{ Header() http.Header }
	if h, ok := ctx.(headerer); ok && h.Header() != nil {
		return bearerTokenFromHeader(h.Header().Get("Authorization"))
	}
	// kernel http.Context embeds context.Context but the wrapper struct
	// exposes Header() through the interface. Fall back to transport
	// header if available.
	type transportHeaderer interface {
		RequestHeader() http.Header
	}
	if th, ok := ctx.(transportHeaderer); ok && th.RequestHeader() != nil {
		return bearerTokenFromHeader(th.RequestHeader().Get("Authorization"))
	}
	return ""
}

func bearerTokenFromHeader(header string) string {
	header = strings.TrimSpace(header)
	if header == "" {
		return ""
	}
	parts := strings.SplitN(header, " ", 2)
	if len(parts) == 2 && strings.EqualFold(parts[0], "Bearer") {
		return strings.TrimSpace(parts[1])
	}
	return ""
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if v != "" {
			return v
		}
	}
	return ""
}

// writeAuthnError writes a JSON error response. The kernel middleware chain
// does not apply to HandleFunc-registered routes, so 302 redirect handlers
// must write errors themselves.
func writeAuthnError(w http.ResponseWriter, status int, err error) {
	w.Header().Set("Content-Type", "application/json; charset=utf-8")
	w.WriteHeader(status)
	_ = json.NewEncoder(w).Encode(map[string]any{
		"code":    status,
		"message": err.Error(),
	})
}

// readJSONBody reads and decodes a JSON request body into dst with a 1MB cap.
// Currently unused (proto-generated handlers decode bodies via ctx.Bind) but
// kept here for symmetry with the legacy backend and for any future manual
// JSON endpoints.
func readJSONBody(r *http.Request, dst any) error {
	defer r.Body.Close()
	body, err := io.ReadAll(io.LimitReader(r.Body, 1<<20))
	if err != nil {
		return err
	}
	if len(body) == 0 {
		return fmt.Errorf("request body is required")
	}
	if err := json.Unmarshal(body, dst); err != nil {
		return fmt.Errorf("invalid JSON body: %w", err)
	}
	return nil
}
